// エンジニアへの実装依頼用イベント仕様書
const eventSpec = [
  {
    // ワークアウト開始イベント
    eventName: '',         // スネークケースで入力
    trigger: '',           // どんな操作で発火するか（日本語で）
    params: {
      workout_type: 'String',  // データ型も記載
      target_duration_min: 'Int'
    },
    swiftExample: ''       // Analytics.logEvent("...", parameters: [...]) の形式
  },
  {
    // プレミアムプラン購入開始イベント
    eventName: '',
    trigger: '',
    params: {
      plan_id: 'String',
      price: 'Double',
      currency: 'String'
    },
    swiftExample: ''
  },
  {
    // チュートリアル完了イベント
    eventName: '',
    trigger: '',
    params: {
      tutorial_id: 'String',
      completion_time_sec: 'Int'
    },
    swiftExample: ''
  }
];

// 仕様書として出力（変更不要）
eventSpec.forEach((spec, i) => {
  console.log(`\n--- イベント ${i + 1} ---`);
  console.log('イベント名:', spec.eventName);
  console.log('発火タイミング:', spec.trigger);
  console.log('パラメータ:', Object.entries(spec.params).map(([k,v]) => `${k}(${v})`).join(', '));
  console.log('Swift実装例:', spec.swiftExample);
});

