const eventSpec = [
  {
    eventName: 'workout_start',
    trigger: 'ワークアウト開始ボタンをタップした時',
    params: {
      workout_type: 'String',
      target_duration_min: 'Int'
    },
    swiftExample: 'Analytics.logEvent("workout_start", parameters: ["workout_type": "running", "target_duration_min": 30])'
  },
  {
    eventName: 'begin_checkout',
    trigger: 'プレミアムプランの購入ボタンをタップした時',
    params: {
      plan_id: 'String',
      price: 'Double',
      currency: 'String'
    },
    swiftExample: 'Analytics.logEvent("begin_checkout", parameters: ["plan_id": "premium_monthly", "price": 980.0, "currency": "JPY"])'
  },
  {
    eventName: 'tutorial_complete',
    trigger: 'チュートリアルの最終ステップを完了した時',
    params: {
      tutorial_id: 'String',
      completion_time_sec: 'Int'
    },
    swiftExample: 'Analytics.logEvent("tutorial_complete", parameters: ["tutorial_id": "onboarding_v2", "completion_time_sec": 145])'
  }
];

eventSpec.forEach((spec, i) => {
  console.log(`\n--- イベント ${i + 1} ---`);
  console.log('イベント名:', spec.eventName);
  console.log('発火タイミング:', spec.trigger);
  console.log('パラメータ:', Object.entries(spec.params).map(([k,v]) => `${k}(${v})`).join(', '));
  console.log('Swift実装例:', spec.swiftExample);
});
